window.PluginManager.register("TechpartsPopupPosition",class{init(){console.log("TechpartsPopupPosition",this.el),this._updatePositions(),this._registerEvents(),this._observeChanges()}_registerEvents(){console.log("_registerEvents",this.el),window.addEventListener("resize",()=>{this._updatePositions()})}_observeChanges(){console.log("_observeChanges",this.el),new MutationObserver(()=>{this._updatePositions()}).observe(this.el,{attributes:!0,subtree:!0,attributeFilter:["style","class"]})}_updatePositions(){console.log("_updatePositions",this.el);let t=this.el.getBoundingClientRect();this.el.querySelectorAll(".hotspot--popup").forEach(e=>{if(console.log("Updating popup position for",e),!e)return;let s=e.getBoundingClientRect();e.classList.remove("popup-left","popup-right");let i=e.offsetWidth,o=t.right-s.right,l=s.left-t.left;o>=i?e.classList.add("popup-right"):l>=i?e.classList.add("popup-left"):e.classList.add("popup-right")})}},".tparts-explosion-box");